"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[933399],{16982:e=>{e.exports=JSON.parse('{"tag":{"label":"transformation","permalink":"/dst-api-webdocs/docs/tags/transformation","allTagsPath":"/dst-api-webdocs/docs/tags","count":35,"items":[{"id":"game-scripts/prefabs/atrium_statue","title":"Atrium Statue","description":"A boss-related interactive statue that dynamically changes appearance based on nightmare phase and drops Thulecite materials when destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/atrium_statue"},{"id":"game-scripts/prefabs/bullkelp_beached","title":"Bullkelp Beached","description":"A grounded bull kelp prefab that transforms into a wet kelp plant and a bullkelp root upon pickup, preserving moisture state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bullkelp_beached"},{"id":"game-scripts/prefabs/chest_mimic","title":"Chest Mimic","description":"A transformable chest entity that hides as a loot chest and attacks players upon opening, functioning as both a container and a hostile monster.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chest_mimic"},{"id":"game-scripts/scenarios/chest_terrarium_pigs","title":"Chest Terrarium Pigs","description":"Triggers a trap when a specific chest is opened, transforming nearby pigs into werepigs and setting them to attack the triggering player.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_terrarium_pigs"},{"id":"game-scripts/prefabs/chester","title":"Chester","description":"Manages the transformation, behavior, and state transitions of the Chester chest monster, including morphing between normal, snow, and shadow variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chester"},{"id":"game-scripts/prefabs/chester_eyebone","title":"Chester Eyebone","description":"Manages the state and behavior of the Chester Eyebone item, including morphing, respawning Chester, and synchronizing with its master.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chester_eyebone"},{"id":"game-scripts/curse_monkey_util","title":"Curse Monkey Util","description":"Manages the application and removal of Monkey Curse effects on an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/curse_monkey_util"},{"id":"game-scripts/components/halloweenpotionmoon","title":"Halloweenpotionmoon","description":"Consumes a Halloween potion item to mutate a target entity via the HalloweenMoonMutable component.","permalink":"/dst-api-webdocs/docs/game-scripts/components/halloweenpotionmoon"},{"id":"game-scripts/prefabs/hedgehound_bush","title":"Hedgehound Bush","description":"Acts as a dormant, thorny flower that transforms into a hedgehound upon activation, rewarding the activator with petals and dealing thorn damage if not protected.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hedgehound_bush"},{"id":"game-scripts/prefabs/hound_corpse","title":"Hound Corpse","description":"A corpse that automatically revives into a mutated hound after a delay unless extinguished or ignited.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hound_corpse"},{"id":"game-scripts/components/itemmimic","title":"Itemmimic","description":"Manages the transformation of an item mimic from an inert object into a hostile entity upon player interaction or time-based triggers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/itemmimic"},{"id":"game-scripts/prefabs/lucy","title":"Lucy","description":"Lucy is a sentient axe prefab that handles speech, equipping/unequipping, container storage, and transformation behaviors in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lucy"},{"id":"game-scripts/prefabs/merm","title":"Merm","description":"Manages core gameplay behaviors for Merm characters, including combat AI, loyalty mechanics, transformation states (shadow/lunar), and royal upgrades.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/merm"},{"id":"game-scripts/components/mightiness","title":"Mightiness","description":"Manages Wolfgang\'s physical transformation system based on his current mightiness level, dynamically adjusting stats, animations, sounds, and gameplay modifiers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mightiness"},{"id":"game-scripts/prefabs/monkey","title":"Monkey","description":"Manages the behavior, state, and lifecycle of the monkey entity, including transformations between normal and nightmare states based on world conditions and external triggers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/monkey"},{"id":"game-scripts/components/moonbeastspawner","title":"Moonbeastspawner","description":"Manages periodic spawning of moonbeasts (moonhounds and moonpigs) near the Moon Base entity and handles petrification of nearby ghouls when active.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moonbeastspawner"},{"id":"game-scripts/prefabs/moondial","title":"Moondial","description":"A world-anchored structure that reflects the current moon phase visually and functionally, enabling gestalt transformation under specific moon conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moondial"},{"id":"game-scripts/prefabs/pigman","title":"Pigman","description":"Manages the behavior, state transitions, and interactions of pig-based characters (normal pig, pig guard, and moonpig), including loyalty mechanics, combat, transformation, and trading.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigman"},{"id":"game-scripts/components/possessedaxe","title":"Possessedaxe","description":"Manages the transformation and reversion logic for Lucy, a possessed axe that links to a woodcutter player and reverts to a standard axe under specific conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/possessedaxe"},{"id":"game-scripts/prefabs/rabbit","title":"Rabbit","description":"Manages the lifecycle, transformations, loot, and interactions of rabbit entities, including seasonal morphing and nightmare-state conversion into beardlings.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbit"},{"id":"game-scripts/prefabs/sapling","title":"Sapling","description":"Manages the lifecycle, interaction, and transformation of sapling entities, including growth, harvesting, transplanting, and optional moon-phase conversion for seasonal variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sapling"},{"id":"game-scripts/stategraphs/SGcanarypoisoned","title":"Sgcanarypoisoned","description":"Manages the animated behavior and transformation sequence of a poisoned canary in DST, including idle loops, hit reactions, explosion, and recovery into a normal canary.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGcanarypoisoned"},{"id":"game-scripts/stategraphs/SGhound","title":"Sghound","description":"Manages the complete state machine for hound-type entities, handling movement, combat, eating, howl-based spawning, transformations (clay/statue), and special states (frozen, electrocuted, moonbase mining).","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGhound"},{"id":"game-scripts/stategraphs/SGmerm","title":"Sgmerm","description":"Manages the state machine for Merm characters, including idle behaviors, transformations, combat, and special animations for lunar or shadow variants.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGmerm"},{"id":"game-scripts/stategraphs/SGwarg","title":"Sgwarg","description":"Manages the state graph for the Warg entity, handling movement, combat (including flamethrower and stagger states), transformation into/instantly from statues, sleep, freeze, electrocute, and lunar rift mutation transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGwarg"},{"id":"game-scripts/stategraphs/SGwerepig","title":"Sgwerepig","description":"Manages the state machine for the Werepig character, handling animations, movement, combat, and transformation between pig and werepig forms.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGwerepig"},{"id":"game-scripts/stategraphs/SGwobysmall","title":"Sgwobysmall","description":"State graph controlling Woby (small form) behavior, including movement, transformations, interactions like picking up items, storing in containers, and various emotes.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGwobysmall"},{"id":"game-scripts/stategraphs/SGworm","title":"Sgworm","description":"Stategraph for the Worm character that manages its transformation between a dormant underground mound and an active above-ground worm state, handling movement, combat, eating, luring, and state transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGworm"},{"id":"game-scripts/prefabs/skilltree_woodie","title":"Skilltree Woodie","description":"Defines the skill tree structure and activation logic for the Woodie character in Don\'t Starve Together, including transformations, allegiance paths, and associated gameplay bonuses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/skilltree_woodie"},{"id":"game-scripts/components/spidermutator","title":"Spidermutator","description":"Handles the conversion of one spider type into another, typically used when a spider consumes a mutator item.","permalink":"/dst-api-webdocs/docs/game-scripts/components/spidermutator"},{"id":"game-scripts/components/transformer","title":"Transformer","description":"Manages switching an entity between two prefabs based on events or world state, preserving component and prefab data across transformations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/transformer"},{"id":"game-scripts/components/werebeast","title":"Werebeast","description":"Manages werebeast transformation logic, including moon phase triggers, manual transformation, and automatic reversion timers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/werebeast"},{"id":"game-scripts/prefabs/wobybig","title":"Wobybig","description":"Manages the behavior, transformation, mounting, and skill-based mechanics of Woby, the large companion pet in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wobybig"},{"id":"game-scripts/prefabs/woodie","title":"Woodie","description":"Manages Woodie\'s transformation between human and three were-forms (beaver, moose, goose) and their associated gameplay mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/woodie"},{"id":"game-scripts/prefabs/wormwood_carrat","title":"Wormwood Carrat","description":"Manages the lifecycle, behavior, and visual state of the Carrat pet summoned by Wormwood during lunar alignment, including its transformation into a carrot upon timer expiry or interaction with an owner.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormwood_carrat"}],"unlisted":false}}')}}]);